if (msg.error) {
  msg.failReason = msg.error;
  return [null, msg];
}

if (!Array.isArray(msg.payload)) {
  msg.failReason = `payload_not_array (${typeof msg.payload})`;
  return [null, msg];
}

if (msg.payload.length !== 216) {
  msg.failReason = `bad_length (${msg.payload.length})`;
  return [null, msg];
}

if (msg.payload.every(v => v === 0)) {
  msg.failReason = "all_zero_payload";
  return [null, msg];
}

return [msg, null];

// Alle registers starten op adres 3000
// index in array = register - 3000

const buffer = new ArrayBuffer(4);
const intView = new Uint32Array(buffer);
const floatView = new Float32Array(buffer);

function readFloat(hi, lo) {
  intView[0] = (hi << 16) | lo;
  return floatView[0].toFixed(3);
}

// INT64 over 4 registers → kWh (eenheid is Wh in register)
function readINT64_kWh(r0, r1, r2, r3) {
  // Controleer op invalid value (0x8000000000000000)
  if (r0 === 0x8000 && r1 === 0 && r2 === 0 && r3 === 0) return null;
  const hi = r0 * 4294967296 + r1 * 65536 + r2;
  // Vereenvoudigd: voor energiewaarden typisch binnen Number.MAX_SAFE_INTEGER
  const val = (r0 * Math.pow(2, 48)) + (r1 * Math.pow(2, 32)) + (r2 * Math.pow(2, 16)) + r3;
  return (val / 1000).toFixed(3); // Wh → kWh
}

const p = msg.payload;
var data = {};

// STROOM (Float32) — offset = register - 3000
data["I1"] = readFloat(p[0],  p[1]);   // reg 3000
data["I2"] = readFloat(p[2],  p[3]);   // reg 3002
data["I3"] = readFloat(p[4],  p[5]);   // reg 3004

// SPANNING fase-fase (Float32)
data["U12"] = readFloat(p[20], p[21]); // reg 3020
data["U23"] = readFloat(p[22], p[23]); // reg 3022
data["U31"] = readFloat(p[24], p[25]); // reg 3024

// SPANNING fase-nul (Float32)
data["U1"] = readFloat(p[28], p[29]); // reg 3028
data["U2"] = readFloat(p[30], p[31]); // reg 3030
data["U3"] = readFloat(p[32], p[33]); // reg 3032

// VERMOGEN per fase (Float32)
data["P1"] = readFloat(p[54], p[55]); // reg 3054
data["P2"] = readFloat(p[56], p[57]); // reg 3056
data["P3"] = readFloat(p[58], p[59]); // reg 3058

// TOTAAL ACTIEF VERMOGEN (Float32)
data["PT"] = readFloat(p[60], p[61]); // reg 3060

// SCHIJNBAAR VERMOGEN totaal (Float32)
data["ST"] = readFloat(p[76], p[77]); // reg 3076

// COS PHI totaal (Float32)
data["PFT"] = readFloat(p[84], p[85]); // reg 3084

// ENERGIE — INT64, 4 registers elk
// reg 3204 → index 204: totaal delivered+received (niet gebruikt)
// reg 3208 → index 208: import (delivered)
// reg 3212 → index 212: export (received)
data["PimpT"] = readINT64_kWh(p[208], p[209], p[210], p[211]); // reg 3208
data["PexpT"] = readINT64_kWh(p[212], p[213], p[214], p[215]); // reg 3212

var nmsg = {};
nmsg.topic = 'telemetry';
nmsg.payload = data;
return nmsg;

let mid = global.get("mid") || 0;

const Dev = "ASSET"; // <-- jouw asset ID

// ID mapping — zelfde structuur als Eastron
const idMapping = {
  "U1":    3000,
  "U2":    3100,
  "U3":    3200,
  "U12":   3050,
  "U23":   3060,
  "U31":   3070,
  "I1":    3300,
  "I2":    3400,
  "I3":    3500,
  "P1":    3600,
  "P2":    3700,
  "P3":    3800,
  "PT":    4200,
  "ST":    4250,
  "PFT":   4400,
  "PimpT": 4600,
  "PexpT": 4500
};

const mappingLower = {};
Object.keys(idMapping).forEach(k => mappingLower[k.toLowerCase()] = idMapping[k]);

let result = {
  MID: mid,
  D: [{
    Dev: Dev,
    ED: [],
    MD: []
  }]
};

const payloadData = msg.payload || {};

for (let key in payloadData) {
  if (!payloadData.hasOwnProperty(key)) continue;

  let id = idMapping[key];
  if (typeof id === "undefined") {
    id = mappingLower[key.toLowerCase()];
  }

  if (typeof id !== "undefined") {
    let rawVal = payloadData[key];
    if (rawVal === null || typeof rawVal === "object") {
      node.warn(`Overslaan ${key}: waarde is null of geen primitief`);
      continue;
    }
    let num = parseFloat(String(rawVal).trim().replace(",", "."));
    if (!Number.isFinite(num)) {
      node.warn(`Ongeldige waarde voor ${key}: "${rawVal}" — overslaan`);
      continue;
    }
    result.D[0].MD.push({ Id: id, Val: num });
  } else {
    node.debug(`Key niet in mapping: ${key}`);
  }
}

result.D[0].TS = new Date().toISOString();

if (result.D[0].MD.length > 0) {
  global.set("mid", mid + 1);
}

msg.payload = result;
msg.queque = "success";
return msg;

let mid = global.get("mid") || 0;

const Dev = "ASSET"; // <-- zelfde asset ID
const MODBUS_FAIL_EVENT_ID = 7199;

let reason = msg.failReason || msg.error || "MODBUS_FAIL";

const unitId = msg.unitId ?? msg.queueUnitId ?? undefined;
const qLen = msg.queueLengthByUnitId?.queueLength ?? msg.queueLength ?? undefined;

let details = [];
if (unitId !== undefined) details.push(`unitId=${unitId}`);
if (qLen   !== undefined) details.push(`queueLen=${qLen}`);
if (msg.topic)     details.push(`topic=${msg.topic}`);
if (msg.messageId) details.push(`messageId=${msg.messageId}`);

let val = String(reason);
if (details.length) val += ` | ${details.join(", ")}`;

const result = {
  MID: mid,
  D: [{
    Dev: Dev,
    ED: [{ Id: MODBUS_FAIL_EVENT_ID, Val: val, Sev: 2 }],
    MD: [],
    TS: new Date().toISOString()
  }]
};

global.set("mid", mid + 1);

msg.payload = result;
msg.queque  = "fail";
msg.topic   = "telemetry";
return msg;

const DELAY_MS = 5000;
const MAX_RETRY = 6;

const Dev = "ASSET";
const RETRY_WARN_EVENT_ID = 7198;

let q = (msg.queque || "").toLowerCase();
let retry = global.get("retry") || 0;

function sendLater(out1, out2, out3) {
  setTimeout(() => node.send([out1, out2, out3]), DELAY_MS);
}

if (q === "fail") {
  retry += 1;
  global.set("retry", retry);

  if (retry < MAX_RETRY) {
    sendLater({ ...msg, action: "go", retry }, null, null);
    return;
  }

  global.set("retry", 0);
  sendLater(null, { ...msg, action: "stop", retry: MAX_RETRY }, null);
  return;
}

if (q === "success") {
  const retriesUsed = retry;

  if (retriesUsed <= 1) {
    global.set("retry", 0);
    sendLater(null, { ...msg, action: "ok", retry: 0 }, null);
    return;
  }

  global.set("retry", 0);

  const m2 = { ...msg, action: "ok_but_retried", info: `success but retried ${retriesUsed} times`, retriesUsed, retry: 0 };

  const mid = global.get("mid") || 0;
  global.set("mid", mid + 1);

  const m3 = {
    topic: "telemetry",
    queque: "event",
    payload: {
      MID: mid,
      D: [{
        Dev,
        ED: [{ Id: RETRY_WARN_EVENT_ID, Val: `success but retried ${retriesUsed} times`, Sev: 2 }],
        MD: [],
        TS: new Date().toISOString()
      }]
    }
  };

  sendLater(null, m2, m3);
  return;
}

sendLater(null, { ...msg, action: "unknown_queque", retry }, null);
